// Scenario 2: Search query and result navigation
// 1. Open /search.
// 2. Assert the empty-state message is shown when there is no query.
// 3. Enter a real query in the navbar search box and trigger Search.
// 4. Assert the URL includes q= and the results summary reflects the searched term.
// 5. Assert at least one result card appears with View and Edit actions.
// 6. Assert the result page exposes Create story, Filter Timeline, and Clear search actions.
// 7. Follow Filter Timeline and assert the filtered timeline route preserves the query string.

import { expect, test } from './helpers/harness.js';
import { EntryFormPage } from './poms/entry-form-page.js';
import { SearchPage } from './poms/search-page.js';

test('scenario 2: search query and result navigation', async ({ ensureDedicatedGroup, page }) => {
  const groupId = await ensureDedicatedGroup();
  const uniqueQuery = `search-scenario-${Date.now()}`;
  const entryFormPage = new EntryFormPage(page);
  const searchPage = new SearchPage(page);

  await entryFormPage.gotoNew();
  await entryFormPage.selectTimelineGroup(groupId);
  await entryFormPage.fillDate('2026', '4', '2');
  await entryFormPage.fillTitle(`Search Scenario Entry ${uniqueQuery}`);
  await entryFormPage.fillEventSummary(`Searchable summary token ${uniqueQuery}.`);
  await entryFormPage.fillTags('search-scenario');
  await entryFormPage.save();

  await expect(page).toHaveURL(/\/entries\/\d+\/view$/);

  await searchPage.goto(groupId);

  await expect(page).toHaveURL(new RegExp(`/search\\?group_id=${groupId}$`));
  await expect(searchPage.searchHeading).toBeVisible();
  await expect(searchPage.emptyStateHeading).toBeVisible();

  await searchPage.search(uniqueQuery);

  await expect(page).toHaveURL(new RegExp(`/search\\?.*group_id=${groupId}.*q=${uniqueQuery}`));
  await expect(searchPage.resultSummary).toContainText(uniqueQuery);

  const firstResultCard = searchPage.firstResultCard();
  await expect(firstResultCard).toBeVisible();
  await expect(firstResultCard.getByRole('link', { name: 'View' })).toBeVisible();
  await expect(firstResultCard.getByRole('link', { name: 'Edit' })).toBeVisible();
  await expect(firstResultCard).toContainText(uniqueQuery);

  await expect(searchPage.createStoryLink).toBeVisible();
  await expect(searchPage.filterTimelineLink).toBeVisible();
  await expect(searchPage.clearSearchLink).toBeVisible();

  await searchPage.openFilteredTimeline();
  await expect(page).toHaveURL(new RegExp(`/\\?.*group_id=${groupId}.*q=${uniqueQuery}`));
  await expect(page.getByRole('heading', { level: 1, name: 'Filtered Timeline' })).toBeVisible();
});